@Transactional(readOnly = true)
fun findMatchingCandidates(userId: String, preferences: MatchingPreferences): List<MatchingCandidate> {
    // 1번 쿼리: 대기 중인 유저 목록 조회
    val waitingUsers = callMatchingRepository.findByStatusAndGender(
        status = MatchingStatus.WAITING,
        gender = preferences.targetGender
    )

    // N번 쿼리: 각 유저마다 프로필 별도 조회 (N+1 발생)
    return waitingUsers.map { matchingUser ->
        val profile = userProfileRepository.findByUserId(matchingUser.userId) // N번 실행
        val mannerScore = userRepository.findById(matchingUser.userId).get().mannerScore // N번 실행

        MatchingCandidate(
            userId = matchingUser.userId,
            nickname = profile?.nickname ?: "",
            mannerScore = mannerScore,
            age = profile?.age ?: 0
        )
    }
}
```

