#### 개선 1: Fetch Join으로 N+1 쿼리 해결

**After (QueryDSL Projection 적용):**

위치: `domain/src/main/kotlin/com/maum/backend/repository/call/CallMatchingRepositoryImpl.kt`

```kotlin
// DTO Projection 클래스
data class MatchingCandidateDto(
    val userId: String,
    val nickname: String,
    val age: Int,
    val gender: Int,
    val mannerScore: Double,
    val profileImageUrl: String?
)

// Repository 구현
class CallMatchingRepositoryImpl(
    private val queryFactory: JPAQueryFactory,
) : CallMatchingCustomRepository {

    override fun findMatchingCandidatesWithProfile(
        excludeUserId: String,
        targetGender: Int,
        minAge: Int,
        maxAge: Int,
        limit: Int,
    ): List<MatchingCandidateDto> {
        val matching = QCallMatchingEntity.callMatchingEntity
        val profile = QUserProfileEntity.userProfileEntity
        val user = QUserEntity.userEntity

        return queryFactory
            .select(
                Projections.constructor(
                    MatchingCandidateDto::class.java,
                    matching.userId,
                    profile.nickname,
                    profile.age,
                    profile.gender,
                    user.mannerScore,
                    profile.profileImageUrl
                )
            )
            .from(matching)
            .innerJoin(profile).on(matching.userId.eq(profile.userId))
            .innerJoin(user).on(matching.userId.eq(user.id))
            .where(
                matching.status.eq(MatchingStatus.WAITING.value),
                matching.userId.ne(excludeUserId),
                profile.gender.eq(targetGender),
                profile.age.between(minAge, maxAge),
                matching.deletedAt.isNull,
            )
            .limit(limit.toLong())
            .fetch()
        // 결과: 쿼리 1회로 필요한 데이터 모두 조회
    }
}
```

예상 개선: 쿼리 201회 -> 1회 (약 95% 감소), 응답 시간 500ms -> 30ms

