@Controller
class CallMatchingController(
    private val callService: CallGrpcService,
    private val userService: UserGrpcService,
) {
    @QueryMapping
    @PreAuthorize("hasAuthority('User')")
    fun matchingStatus(@UserId userId: String): MatchingStatusResponse {
        // Before: 순차 호출 310ms
        // After: 병렬 호출 (가장 느린 단일 호출 시간 = 100ms)

        return runBlocking {
            val matchingInfoDeferred = async { callService.getMatchingStatus(userId) }
            val userProfileDeferred = async { userService.getUserProfile(userId) }
            val mannerScoreDeferred = async { callService.getMannerScore(userId) }
            val blockListDeferred = async { userService.getBlockList(userId) }

            val matchingInfo = matchingInfoDeferred.await()   // 100ms (병렬)
            val userProfile = userProfileDeferred.await()     // 80ms  (병렬)
            val mannerScore = mannerScoreDeferred.await()     // 60ms  (병렬)
            val blockList = blockListDeferred.await()         // 70ms  (병렬)
            // 총 100ms (가장 느린 요청 기준)

            MatchingStatusResponse(
                status = matchingInfo.status,
                nickname = userProfile.nickname,
                mannerScore = mannerScore.score,
                blockedCount = blockList.count
            )
        }
    }
}
